#define TRIG 3
#define ECHO 4
#define G_IN1 7
#define G_IN2 8
#define G_ENA 6
#define BUZZER 9
#define LED 10
#define SD_CS 5
#define SENSOR_H 0.70f
#define CH_W 0.30f
#define N_ROUGH 0.013f
#define S_SLOPE 0.005f
#define CAP_RATIO 0.85f
#include <SD.h>
float intg=0,lastE=0;
bool firstFlush=true;
unsigned long ffStart=0;

float manning_flow_rate(float n,float R,float S,float A){return (1.0f/n)*pow(R,2.0f/3.0f)*sqrt(S)*A;}

float read_depth(){
  digitalWrite(TRIG,LOW);delayMicroseconds(2);
  digitalWrite(TRIG,HIGH);delayMicroseconds(10);digitalWrite(TRIG,LOW);
  return SENSOR_H-(pulseIn(ECHO,HIGH)*0.000343f/2.0f);
}

float depth_to_Q(float d){
  if(d<=0)return 0;
  float A=CH_W*d,P=CH_W+2*d;
  return manning_flow_rate(N_ROUGH,A/P,S_SLOPE,A);
}

float Q_max(){float d=0.25f,A=CH_W*d,P=CH_W+2*d;return manning_flow_rate(N_ROUGH,A/P,S_SLOPE,A);}

void set_gate(int cmd){
  if(cmd==0){digitalWrite(G_IN1,LOW);digitalWrite(G_IN2,LOW);analogWrite(G_ENA,0);}
  else if(cmd==1){digitalWrite(G_IN1,HIGH);digitalWrite(G_IN2,LOW);analogWrite(G_ENA,128);}
  else{digitalWrite(G_IN1,HIGH);digitalWrite(G_IN2,LOW);analogWrite(G_ENA,255);}
}

void run_alarm(float r){if(r>=0.95f){tone(BUZZER,2000);analogWrite(LED,255);}else{noTone(BUZZER);analogWrite(LED,(int)(r*200));}}

void log_event(float d,float r){File f=SD.open("drain.csv",FILE_WRITE);if(f){f.print(millis());f.print(',');f.print(d);f.print(',');f.println(r);f.close();}}

void setup(){Serial.begin(115200);pinMode(TRIG,OUTPUT);pinMode(ECHO,INPUT);pinMode(G_IN1,OUTPUT);pinMode(G_IN2,OUTPUT);pinMode(G_ENA,OUTPUT);pinMode(BUZZER,OUTPUT);pinMode(LED,OUTPUT);SD.begin(SD_CS);ffStart=millis();}

void loop(){
  float d=read_depth(),Q=depth_to_Q(d),Qm=Q_max(),r=Q/Qm;
  if(firstFlush&&(millis()-ffStart<600000)){set_gate(0);}else{firstFlush=false;set_gate(r>0.95f?2:(r>CAP_RATIO)?1:0);}
  run_alarm(r);log_event(d,r);
  Serial.print("r=");Serial.println(r);
  delay(500);
}
